import re
from pathlib import Path

import pytest

AC_UID = "9d727e2e84112856"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
QA_MD = REPO_ROOT / "agents" / "qa.md"


def _slice(text: str, start_re: str, end_re: str) -> str:
    m_start = re.search(start_re, text, re.MULTILINE)
    assert m_start, f"start anchor {start_re!r} not found in agents/qa.md"
    rest = text[m_start.start():]
    m_end = re.search(end_re, rest[1:], re.MULTILINE)
    end_pos = m_end.start() + 1 if m_end else len(rest)
    return rest[:end_pos]


def test_AC_04():
    """
    GIVEN: agents/qa.md is read as text
    WHEN:  Phase 5 section AND the manifest_verification schema block are inspected separately (each scope-anchored)
    THEN:  Phase 5 step 1 reads the per-task manifest (not global); pytest is per-task-scoped; the schema's manifest_path is per-task; the legitimate global-index PRESENCE sentinel inside Phase 5 references the global path explicitly as 'tests/generated/manifest.json is missing'
    """
    assert QA_MD.is_file(), f"missing: {QA_MD}"
    src = QA_MD.read_text(encoding="utf-8")

    phase5 = _slice(src, r"^#### Phase 5: Manifest Verification", r"^#### Phase 6:")
    assert "tests/generated/<task_id>/manifest.json" in phase5, (
        "agents/qa.md Phase 5 missing per-task manifest path reference"
    )
    assert re.search(r"pytest\s+tests/generated/<task_id>/", phase5), (
        "agents/qa.md Phase 5 missing per-task-scoped pytest invocation"
    )
    assert re.search(
        r"test_writer_expected[^\n]{0,400}tests/generated/manifest\.json is missing",
        phase5,
        re.DOTALL,
    ), "agents/qa.md Phase 5 missing the test_writer_expected/global-index 'missing' sentinel"
    assert not re.search(
        r"Read `tests/generated/manifest\.json`\.\s+For every `active_tests\[\]` entry",
        phase5,
    ), "agents/qa.md Phase 5 still uses Cycle-1-drift global-active_tests phrasing"

    schema = _slice(src, r'"manifest_verification"\s*:\s*\{', r'^\s*\},\s*$|^\s*"blast_radius_phase2"')
    assert re.search(r'"manifest_path"\s*:\s*"tests/generated/<task_id>/manifest\.json"', schema), (
        "agents/qa.md manifest_verification schema missing per-task manifest_path"
    )
    assert not re.search(r'"manifest_path"\s*:\s*"tests/generated/manifest\.json"', schema), (
        "agents/qa.md manifest_verification schema incorrectly uses global manifest_path"
    )
